def validate(args, output):
    n = args[0]
    if not isinstance(output, list):
        return False
    if len(output) != n:
        return False
    for v in output:
        if not isinstance(v, int) or isinstance(v, bool):
            return False
    if len(set(output)) != n:
        return False
    return sum(output) == 0

